using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// --- Tools ---
var notebook = new Notebook();
var searcher = new WebSearcher();

var tools = new AITool[]
{
    AIFunctionFactory.Create(searcher.SearchAsync),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.ReadNotes),
};

// --- Chat client with automatic tool invocation ---
IChatClient client = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(model).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

// --- Prompt ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Thoroughly research the given topic using the
        tools at your disposal. Follow this process:

        1. Perform 2-3 web searches with varied queries to cover different angles.
        2. After each search, save the most important findings as notes.
        3. Once you have gathered enough information, read back all your notes.
        4. Write a well-structured summary that synthesizes your findings,
           including key facts, different perspectives, and source URLs.

        Always save notes before moving on to the next search.
        """),
    new(ChatRole.User, $"Research this topic: {topic}"),
};

var response = await client.GetResponseAsync(messages, new ChatOptions { Tools = tools });

Console.WriteLine("\n═══════════════════════════════════════");
Console.WriteLine("📋  RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════\n");
Console.WriteLine(response.Text);

// ─────────────────────────────────────────────────────────────
// Tool implementations
// ─────────────────────────────────────────────────────────────

/// <summary>Simple in-memory notebook the agent uses to record findings.</summary>
sealed class Notebook
{
    private readonly List<string> _notes = [];

    [Description("Save a research note. Call this after every web search to record key findings.")]
    public string AddNote(
        [Description("The note text to save")] string content)
    {
        _notes.Add(content);
        var preview = content.Length > 100 ? content[..100] + "…" : content;
        Console.WriteLine($"  📝 Note #{_notes.Count} saved – {preview}");
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all research notes collected so far.")]
    public string ReadNotes()
    {
        if (_notes.Count == 0) return "No notes yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
            sb.AppendLine($"[{i + 1}] {_notes[i]}");
        Console.WriteLine($"  📖 Retrieved {_notes.Count} note(s)");
        return sb.ToString();
    }
}

/// <summary>Searches DuckDuckGo HTML and returns the top results.</summary>
sealed class WebSearcher
{
    private static readonly HttpClient Http = new();

    [Description("Search the web and return the top results with titles, URLs, and snippets.")]
    public async Task<string> SearchAsync(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");
        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";

            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd(
                "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

            using var response = await Http.SendAsync(request);
            response.EnsureSuccessStatusCode();
            var html = await response.Content.ReadAsStringAsync();

            var results = ParseResults(html);
            if (results.Count == 0) return $"No results found for: {query}";

            var sb = new StringBuilder();
            sb.AppendLine($"Results for \"{query}\":\n");
            foreach (var (title, snippet, link) in results)
            {
                sb.AppendLine($"• {title}");
                sb.AppendLine($"  {link}");
                sb.AppendLine($"  {snippet}\n");
            }
            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static List<(string Title, string Snippet, string Url)> ParseResults(
        string html)
    {
        var items = new List<(string, string, string)>();

        var titles   = Regex.Matches(html,
            @"<a[^>]*class=""result__a""[^>]*>(.*?)</a>", RegexOptions.Singleline);
        var snippets = Regex.Matches(html,
            @"<a[^>]*class=""result__snippet""[^>]*>(.*?)</a>", RegexOptions.Singleline);
        var urls     = Regex.Matches(html,
            @"<a[^>]*class=""result__url""[^>]*href=""([^""]*?)""[^>]*>",
            RegexOptions.Singleline);

        var count = Math.Min(titles.Count, Math.Min(snippets.Count, urls.Count));
        for (var i = 0; i < count && i < 5; i++)
        {
            var title   = Strip(titles[i].Groups[1].Value);
            var snippet = Strip(snippets[i].Groups[1].Value);
            var link    = WebUtility.HtmlDecode(urls[i].Groups[1].Value).Trim();

            if (!string.IsNullOrWhiteSpace(title))
                items.Add((title, snippet, link));
        }
        return items;
    }

    private static string Strip(string html)
    {
        var text = Regex.Replace(html, "<.*?>", "");
        return WebUtility.HtmlDecode(text).Trim();
    }
}

